    .earnings-row{display:flex;align-items:baseline;gap:8px}
    .earnings-val{font-size:24px;color:var(--text);font-weight:400}
    .earnings-note{font-size:11px;color:var(--dim);margin-top:8px}

    .funding{background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:16px 18px;margin-bottom:24px}
    .funding-title{font-size:12px;color:var(--amber);margin-bottom:8px}
    .funding-text{font-size:11px;color:var(--secondary);line-height:1.6}

    footer{padding:24px 0;border-top:1px solid var(--border);margin-top:24px}
    .footer-text{font-size:10px;color:var(--dim)}
